const response = $input.first().json;
const pulses = response.results || [];

let domains = [];
let ips = [];
let urls = [];
let hashes = [];

// Loop through each pulse and extract indicators
pulses.forEach(pulse => {
  const indicators = pulse.indicators || [];
  const pulseName = pulse.name;
  const adversary = pulse.adversary || 'Unknown';

  indicators.forEach(indicator => {
    const ioc = {
      value: indicator.indicator,
      type: indicator.type,
      pulse: pulseName,
      adversary,
      created: indicator.created
    };

    if (indicator.type === 'domain') domains.push(ioc);
    else if (indicator.type === 'IPv4') ips.push(ioc);
    else if (indicator.type === 'URL') urls.push(ioc);
    else if (['MD5','SHA256','SHA1'].includes(indicator.type)) hashes.push(ioc);
  });
});

// Summary stats
const totalIOCs = domains.length + ips.length + urls.length + hashes.length;

return [{
  json: {
    fetchedAt: new Date().toISOString(),
    totalIOCs,
    totalDomains: domains.length,
    totalIPs: ips.length,
    totalURLs: urls.length,
    totalHashes: hashes.length,
    domains,
    ips,
    urls,
    hashes
  }
}];

const response = $input.first().json;
const urls = response.urls || [];

// Extract unique malicious IPs and URLs
let maliciousIPs = [];
let maliciousURLs = [];

urls.forEach(entry => {
  if (entry.url_status === 'online') {
    maliciousURLs.push({
      url: entry.url,
      host: entry.host,
      threat: entry.threat,
      tags: entry.tags || [],
      reported: entry.date_added,
      reference: entry.urlhaus_reference
    });

    // Extract IP if host is an IP address
    const ipRegex = /^(\d{1,3}\.){3}\d{1,3}$/;
    if (ipRegex.test(entry.host)) {
      maliciousIPs.push({
        ip: entry.host,
        threat: entry.threat,
        tags: entry.tags || [],
        reported: entry.date_added
      });
    }
  }
});

// Deduplicate IPs
const uniqueIPs = [...new Map(
  maliciousIPs.map(item => [item.ip, item])
).values()];

return [{
  json: {
    source: 'Abuse.ch URLhaus',
    fetchedAt: new Date().toISOString(),
    totalURLs: maliciousURLs.length,
    totalMaliciousIPs: uniqueIPs.length,
    maliciousURLs,
    maliciousIPs: uniqueIPs
  }
}];

const item = $input.first().json;

// Data is already merged into one item
// AlienVault data
const otxDomains = item.domains || [];
const otxIPs = item.ips || [];
const otxURLs = item.urls || [];

// Abuse.ch data
const abuseIPs = item.maliciousIPs || [];
const abuseURLs = item.maliciousURLs || [];

// Combine all IPs
const allIPs = [...otxIPs, ...abuseIPs];
const allDomains = [...otxDomains];
const allURLs = [...otxURLs, ...abuseURLs];

// Deduplicate IPs
const uniqueIPs = [...new Map(
  allIPs.map(i => [i.ip || i.value, i])
).values()];

// Deduplicate domains
const uniqueDomains = [...new Map(
  allDomains.map(d => [d.value, d])
).values()];

// Top 5 preview for Discord
const topIPs = uniqueIPs.slice(0, 5)
  .map(i => `${i.ip || i.value} (${i.threat || 'malicious'})`)
  .join('\n');

const topDomains = uniqueDomains.slice(0, 5)
  .map(d => `${d.value} (${d.adversary || 'unknown'})`)
  .join('\n');

const totalIOCs = uniqueIPs.length + uniqueDomains.length + allURLs.length;

return [{
  json: {
    fetchedAt: new Date().toISOString(),
    totalIOCs,
    totalIPs: uniqueIPs.length,
    totalDomains: uniqueDomains.length,
    totalURLs: allURLs.length,
    topIPs,
    topDomains,
    uniqueIPs,
    uniqueDomains,
    allURLs
  }
}];

